import { describe, it, expect } from 'vitest'
import bruteForceSubstring from './solutions/brute-force-substring'
import bruteForceIndex from './solutions/brute-force-index'

type Case = {
    name: string
    str: string
    expected: string[]
}

const cases: Case[] = [
    {
        name: 'example 1',
        str: 'babad',
        expected: ['aba', 'bab']
    },
    {
        name: 'example 2',
        str: 'cbbd',
        expected: ['bb']
    },
    {
        name: 'example 3',
        str: 'a',
        expected: ['a']
    },
    {
        name: 'TLE when time complexity is O(n^3)',
        str: '',
        expected: ['']
    }
]

const solutions = [
    { name: 'brute-force-substring', fn: bruteForceSubstring },
    { name: 'brute-force-index', fn: bruteForceIndex }
]

describe('0005 - Longest Palindromic Substring', () => {
    for (const solution of solutions) {
        describe(solution.name, () => {
            for (const c of cases) {
                it(c.name, () => {
                    const result = solution.fn(c.str)
                    expect(c.expected).toContain(result)
                })
            }
        })
    }
})
